+        }
+
+        count
+    }
+
+    /// Draw all nodes.
+    fn draw_nodes<C: Canvas2dContext>(
+        &mut self,
+        layout: &DiagramLayout,
+        ir: &MermaidDiagramIr,
+        ctx: &mut C,
