+        ir
+    }
+
+    #[test]
+    fn describe_diagram_includes_counts() {
+        let ir = create_test_ir();
+        let desc = describe_diagram(&ir);
+        assert!(desc.contains("2 nodes"));
+        assert!(desc.contains("0 edges"));
