+
+    #[test]
+    fn a11y_config_full_enables_all() {
+        let config = A11yConfig::full();
+        assert!(config.aria_labels);
+        assert!(config.text_alternatives);
+        assert!(config.keyboard_nav);
+        assert!(config.accessibility_css);
